import{_ as o,C as r,o as s,c as i,a2 as a,E as n}from"./chunks/framework.BKG_UbFK.js";const _=JSON.parse('{"title":"डैशबोर्ड","description":"","frontmatter":{},"headers":[],"relativePath":"hi/features/dashboard.md","filePath":"hi/features/dashboard.md"}'),l={name:"hi/features/dashboard.md"};function c(d,e,h,p,u,f){const t=r("Screenshot");return s(),i("div",null,[e[0]||(e[0]=a('<h1 id="डैशबोर्ड" tabindex="-1">डैशबोर्ड <a class="header-anchor" href="#डैशबोर्ड" aria-label="Permalink to &quot;डैशबोर्ड&quot;">​</a></h1><p>डैशबोर्ड, Clearance पैनल का लैंडिंग पेज है। यह आपके एप्लिकेशन की प्राधिकरण स्थिति का एक नज़र में सारांश देता है - किसी कॉन्फ़िगरेशन की आवश्यकता नहीं।</p><h2 id="यह-क्या-दिखाता-है" tabindex="-1">यह क्या दिखाता है <a class="header-anchor" href="#यह-क्या-दिखाता-है" aria-label="Permalink to &quot;यह क्या दिखाता है&quot;">​</a></h2><ul><li><strong>कुल भूमिकाएं</strong> - सभी Spatie भूमिकाओं की गिनती।</li><li><strong>कुल गार्ड</strong> - Clearance द्वारा प्रबंधित सभी गार्ड्स की गिनती (देखें <a href="/clearance-docs/hi/features/guards.html">गार्ड</a>)।</li><li><strong>कुल अनुमतियाँ</strong> - सभी Spatie अनुमतियों की गिनती।</li><li><strong>अनुमति समूह</strong> - अलग-अलग अनुमति समूहों की संख्या, नामकरण prefix से प्राप्त (<code>group-action</code> में <code>group</code>, जैसे <code>orders-create</code> में <code>orders</code>)। नामकरण परंपरा के लिए देखें <a href="/clearance-docs/hi/features/permissions.html">अनुमतियाँ</a>।</li><li><strong>प्रासंगिक भूमिका असाइनमेंट</strong> - किसी विशिष्ट मॉडल इंस्टेंस (एक Store, एक Tenant, एक Project) तक सीमित भूमिका असाइनमेंट की संख्या। देखें <a href="/clearance-docs/hi/features/contextual-authorization.html">प्रासंगिक प्राधिकरण</a>।</li><li><strong>उपयोगकर्ता संख्या के अनुसार शीर्ष 5 भूमिकाएं</strong> - सबसे अधिक असाइन किए गए उपयोगकर्ताओं वाली पांच भूमिकाएं, क्रमबद्ध।</li></ul>',4)),n(t,{src:"/screenshots/dashboard-page.png",alt:"Clearance डैशबोर्ड जो भूमिका, गार्ड और अनुमति की गिनती दिखा रहा है",caption:"डैशबोर्ड भूमिकाओं, गार्ड्स, अनुमतियों, समूहों, प्रासंगिक असाइनमेंट, और शीर्ष भूमिकाओं का सारांश देता है।"}),e[1]||(e[1]=a('<h2 id="डैशबोर्ड-तक-पहुंचना" tabindex="-1">डैशबोर्ड तक पहुंचना <a class="header-anchor" href="#डैशबोर्ड-तक-पहुंचना" aria-label="Permalink to &quot;डैशबोर्ड तक पहुंचना&quot;">​</a></h2><table tabindex="0"><thead><tr><th>URI</th><th>Route नाम</th><th>विवरण</th></tr></thead><tbody><tr><td><code>/clearance</code></td><td><code>clearance.home</code></td><td>डैशबोर्ड</td></tr></tbody></table><p>डैशबोर्ड को पढ़ने के लिए <code>clearance-access</code> अनुमति आवश्यक है, बाकी हर पैनल सेक्शन की तरह। पूरी access-control टेबल के लिए देखें <a href="/clearance-docs/hi/features/super-admin.html#panel-access-fine-grained-write-permissions">सुपर एडमिन</a>।</p><h2 id="component-को-एम्बेड-करना" tabindex="-1">Component को एम्बेड करना <a class="header-anchor" href="#component-को-एम्बेड-करना" aria-label="Permalink to &quot;Component को एम्बेड करना&quot;">​</a></h2><p>डैशबोर्ड एक स्वतंत्र (self-contained) Livewire component है। इसे पहले से बने <code>/clearance</code> route के बजाय - या उसके साथ - अपने खुद के layouts में कहीं भी माउंट करें:</p><div class="language-blade vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">blade</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">livewire:clearance::dashboard</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span></code></pre></div><h2 id="अगले-कदम" tabindex="-1">अगले कदम <a class="header-anchor" href="#अगले-कदम" aria-label="Permalink to &quot;अगले कदम&quot;">​</a></h2><ul><li><a href="/clearance-docs/hi/features/permissions.html">अनुमतियाँ</a> - डैशबोर्ड की गिनती को feed करने वाली अनुमति सूची को प्रबंधित करें।</li><li><a href="/clearance-docs/hi/features/roles.html">भूमिकाएं</a> - &quot;उपयोगकर्ता संख्या के अनुसार शीर्ष 5&quot; आंकड़े के पीछे की भूमिकाओं को प्रबंधित करें।</li><li><a href="/clearance-docs/hi/features/contextual-authorization.html">प्रासंगिक प्राधिकरण</a> - प्रासंगिक भूमिका असाइनमेंट क्या है।</li></ul>',8))])}const g=o(l,[["render",c]]);export{_ as __pageData,g as default};
